/**
 * @fileoverview Tabs component — modular entry point.
 *
 * Orchestrates sub-modules:
 *   constants.js — CSS classes, ARIA attrs, default config
 *   helpers.js   — tab navigation utility
 *   state.js     — pure SM transitions + reactive state wiring
 *   view.js      — DOM setup / teardown + SM effects
 *   events.js    — centralised event binding (AbortController cleanup)
 *
 * @module module/Tabs
 */

import { default as razyui } from '../../index.js';
import { StateMachine } from '../shared/StateMachine.js';
import { TabsDef as DEF } from '../Tabs.def.js';

import { DEFAULTS, SEL, CLS }                          from './constants.js';
import { findNextTab }                                  from './helpers.js';
import { TAB_TRANSITIONS, createReactiveState }         from './state.js';
import { SM_EFFECTS, setupRoot, setupList, setupTabARIA, cleanupDOM } from './view.js';
import { createHandlerCtx, bindEvents }                 from './events.js';

/**
 * Tabs — tabbed interface component (JIT-compatible)
 *
 * Enhances a container with tab buttons and associated panels into an
 * accessible, keyboard-navigable tabbed interface.
 *
 * Features:
 *   - Horizontal & vertical orientation
 *   - Three variants: default (underline), boxed, pills
 *   - Closable / removable tabs
 *   - Automatic vs manual activation mode
 *   - Full ARIA tablist/tab/tabpanel support
 *   - Keyboard navigation (← → ↑ ↓ Home End)
 *   - Disabled tab support
 *   - Icon slots in tabs
 *   - Callbacks: onSelect, onClose
 *   - Programmatic API: select(), close(), getControl()
 *
 * @param {string|Element} selector — CSS selector or Element for the root container
 * @param {object}   [config]
 * @param {number}   [config.activeIndex=0]      — initial tab index
 * @param {string}   [config.variant]             — 'boxed' | 'pills'
 * @param {string}   [config.orientation='horizontal'] — 'horizontal' | 'vertical'
 * @param {string}   [config.activation='automatic']   — 'automatic' | 'manual'
 * @param {boolean}  [config.closable=false]      — show close button on tabs
 * @param {function} [config.onSelect]            — (index, panel, button) => void
 * @param {function} [config.onClose]             — (index, button) => boolean|void (return false to cancel)
 */
const Tabs = class {
    #root = null;          // the outer container
    #destroyed = false;
    #list = null;          // the tab list row/column
    #tabs = [];            // ordered array of tab button elements
    #panels = new Map();   // Map<button, Element> resolved panels
    #tabSMs = [];          // per-tab StateMachine instances
    #config = {};
    #stateRef = null;
    #setState = null;
    #uid = 0;              // unique id counter for ARIA linking
    #eventAC = null;       // AbortController for event cleanup

    static #counter = 0;

    constructor(selector, config = {}) {
        const root = razyui(selector);

        if (!root.length) {
            console.warn('Tabs: element not found \u2192', selector);
            return;
        }

        this.#root = root;
        this.#config = { ...DEFAULTS, ...config };
        this.#uid = ++Tabs.#counter;

        this.#init();
    }

    #init() {
        const config = this.#config;
        const root = this.#root;
        const uid = this.#uid;

        // 1. View: setup root container
        setupRoot(root, config);

        // 2. Find or create list element — first child with [role="tablist"] or first child
        let listEl = root.find('[role="tablist"]');
        if (!listEl.length) {
            // Use the first child element that contains tab buttons
            const firstChild = root.children(':first-child');
            if (firstChild.length && firstChild.find(SEL.TAB).length) {
                listEl = firstChild;
            } else {
                // The root itself contains tabs directly
                listEl = root;
            }
        }
        this.#list = listEl;
        setupList(listEl, config);

        // 3. Gather tab buttons
        this.#tabs = listEl.find(SEL.TAB);

        // 4. Resolve panels + ARIA + per-tab state machines
        const smConfig = { ...TAB_TRANSITIONS, effects: SM_EFFECTS };
        this.#tabs.each((btn, i) => {
            const button = razyui(btn);
            const panelSel = button.attr('data-tab');
            const panel = razyui(panelSel);

            if (!panel.length) {
                console.warn('Tabs: panel not found →', panelSel);
                return;
            }

            this.#panels.set(btn, panel);
            setupTabARIA(button, panel, uid, i, config);

            const sm = new StateMachine(smConfig, { button, panel, index: i });
            if (btn.disabled || button.hasClass(CLS.DISABLED)) {
                sm.reset('disabled');
                SM_EFFECTS.disabled({ button, panel });
            }
            this.#tabSMs.push(sm);
        });

        // 5. Reactive state — wired to SM synchronisation
        const { ref, setState } = createReactiveState(razyui.state, this.#tabSMs);
        this.#stateRef = ref;
        this.#setState = setState;

        // 6. Events — centralised binding with AbortController cleanup
        const ctx = createHandlerCtx(() => ({
            tabs:        this.#tabs,
            activeIndex: this.#stateRef.activeIndex,
            orientation: this.#config.orientation,
            activation:  this.#config.activation,
            select:      i => this.select(i),
            close:       i => this.close(i),
            findNextTab: (from, dir) => findNextTab(this.#tabs, from, dir),
        }));
        this.#eventAC = bindEvents(this.#list, ctx);

        // 7. Initial selection
        const initialIndex = config.activeIndex ?? DEFAULTS.activeIndex;
        const firstEnabled = findNextTab(this.#tabs, initialIndex - 1, 1, false)
            ?? findNextTab(this.#tabs, -1, 1);
        if (firstEnabled >= 0) this.select(firstEnabled);
    }

    // ── Public API ──

    /** Select a tab by index. */
    select(index) {
        const tabs = this.#tabs;
        if (index < 0 || index >= tabs.length) return;
        if (tabs[index].disabled) return;

        const prev = this.#stateRef.activeIndex;
        if (prev === index) return;

        this.#setState({ activeIndex: index });

        if (typeof this.#config.onSelect === 'function') {
            const panel = this.#panels.get(tabs[index]);
            this.#config.onSelect.call(this, index, panel, tabs[index]);
        }
    }

    /**
     * Close (remove) a tab by index.
     * Fires onClose callback — return false to cancel.
     */
    close(index) {
        const tabs = this.#tabs;
        if (index < 0 || index >= tabs.length) return;

        // Callback can cancel
        if (typeof this.#config.onClose === 'function') {
            const result = this.#config.onClose.call(this, index, tabs[index]);
            if (result === false) return;
        }

        const btn = tabs[index];
        const panel = this.#panels.get(btn);
        const wasActive = this.#stateRef.activeIndex === index;

        // Remove from DOM
        razyui(btn).remove();
        if (panel) panel.remove();

        // Cleanup maps
        this.#panels.delete(btn);
        this.#tabs.splice(index, 1);
        this.#tabSMs.splice(index, 1);

        // If the closed tab was active, select next available
        if (wasActive) {
            const next = findNextTab(this.#tabs, index - 1, 1)
                ?? findNextTab(this.#tabs, index, -1);
            if (next >= 0) {
                this.#setState({ activeIndex: -1 }); // force change
                this.select(next);
            } else {
                this.#setState({ activeIndex: -1 });
            }
        } else if (this.#stateRef.activeIndex > index) {
            // Adjust active index if a tab before the active one was removed
            this.#setState({ activeIndex: this.#stateRef.activeIndex - 1 });
        }
    }

    /** Get the current active tab index. */
    get activeIndex() {
        return this.#stateRef.activeIndex;
    }

    /** Get the array of tab button elements. */
    get tabs() {
        return [...this.#tabs];
    }

    /** Get the panel element for a tab index. */
    getPanel(index) {
        return this.#panels.get(this.#tabs[index]) || null;
    }

    /** Enable/disable a tab by index. */
    setDisabled(index, disabled) {
        const sm = this.#tabSMs[index];
        if (!sm) return;

        if (disabled && sm.current !== 'disabled') {
            if (this.#stateRef.activeIndex === index) {
                const next = findNextTab(this.#tabs, index, 1);
                const target = next >= 0 ? next : findNextTab(this.#tabs, index, -1);
                if (target >= 0) this.select(target);
            }
            sm.reset('disabled');
            const btn = razyui(this.#tabs[index]);
            const panel = this.#panels.get(this.#tabs[index]);
            SM_EFFECTS.disabled({ button: btn, panel });
        } else if (!disabled && sm.current === 'disabled') {
            sm.send('ENABLE');
            if (this.#stateRef.activeIndex === index) {
                sm.send('SELECT');
            }
        }
    }

    /**
     * Get a reactive control object with get/set properties.
     * @returns {object}
     */
    getControl() {
        const self = this;
        return {
            get activeIndex() { return self.#stateRef.activeIndex; },
            set activeIndex(v) { self.select(v); },
            get orientation() { return self.#config.orientation; },
            get variant() { return self.#config.variant; },
            set variant(v) { self.#config.variant = v; },
            get activation() { return self.#config.activation; },
            set activation(v) { self.#config.activation = v; },
            get closable() { return self.#config.closable; },
            set closable(v) { self.#config.closable = !!v; },
            setDisabled: (i, d) => self.setDisabled(i, d),
            next: () => {
                const next = findNextTab(self.#tabs, self.#stateRef.activeIndex, 1);
                if (next >= 0) self.select(next);
            },
            prev: () => {
                const prev = findNextTab(self.#tabs, self.#stateRef.activeIndex, -1);
                if (prev >= 0) self.select(prev);
            },
            tabs:    self.tabs,
            destroy: () => self.destroy(),
            get element() { return self.#root[0]; },
            get destroyed() { return self.#destroyed; },
        };
    }

    /** Cleanup — remove ARIA, classes, and event listeners. */
    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.#eventAC?.abort();
        cleanupDOM(this.#root, this.#list, this.#tabs, this.#panels, this.#config);
        this.#panels.clear();
        this.#tabSMs.length = 0;
    }
};

export default Tabs;
