/**
 * @fileoverview Tabs component definition for JIT pipeline.
 *
 * Bundles design tokens, state machine config, template slot definitions,
 * event handler abstractions, and Custom Element metadata.
 *
 * @module module/Tabs.def
 */

import razyui from '../index.js';
import { PART, SEL } from './Tabs/constants.js';

/**
 * Definition object for the Tabs component.
 * @type {object}
 */
export const TabsDef = {
    name: 'Tabs',
    tag: 'rui-tabs',

    // ═════════════════════════════════════
    //  Design Tokens
    // ═════════════════════════════════════
    tokens: {
        prefix: 'tb',
        tokens: {
            'font-size':        { ref: 'font.size-sm',       description: 'Base font size' },
            'padding-x':        { value: '0.5rem',           description: 'List horizontal padding' },
            'tab-padding-x':    { ref: 'spacing.4',          description: 'Tab horizontal padding' },
            'tab-padding-y':    { ref: 'spacing.2',          description: 'Tab vertical padding' },
            'tab-gap':          { value: '0.25rem',          description: 'Gap within tab button (icon ↔ label)' },
            'tab-font-weight':  { value: '500',              description: 'Tab font weight' },
            'tab-line-height':  { value: '1.25',             description: 'Tab line height' },
            'tab-radius':       { ref: 'radius.sm',          description: 'Tab corner radius' },
            'content-padding':  { value: '1rem',              description: 'Panel content padding' },
            'radius':           { ref: 'radius.md',          description: 'Container border radius' },
            'accent':           { ref: 'color.accent',       description: 'Active tab accent color' },
            'bg':               { ref: 'color.bg',           description: 'Panel background' },
            'bg-header':        { ref: 'color.bg-raised',    description: 'Tab header background' },
            'bg-hover':         { ref: 'color.bg-hover',     description: 'Tab hover background' },
            'bg-inset':         { ref: 'color.bg-inset',     description: 'Pills container background' },
            'border':           { ref: 'color.border',       description: 'Border color' },
            'shadow-sm':        { ref: 'shadow.sm',          description: 'Pills active shadow' },
            'text':             { ref: 'color.text',         description: 'Tab text color' },
            'text-muted':       { ref: 'color.text-muted',   description: 'Inactive tab text' },
            'font-stack':       { ref: 'font.family',        description: 'Font family' },
        },
    },

    // ═════════════════════════════════════
    //  State Machine (per-tab-item)
    // ═════════════════════════════════════
    states: {
        initial: 'inactive',
        states: {
            inactive: { on: { SELECT: 'active' } },
            active:   { on: { DESELECT: 'inactive' } },
            disabled: { on: { ENABLE: 'inactive' } },
        },
        effects: {
            active(ctx) {
                const { button, panel } = ctx;
                razyui(button).setAttr({ 'aria-selected': 'true', tabindex: '0' })
                    .addClass('is-active');
                if (panel) {
                    panel.hidden = false;
                    razyui(panel).addClass('is-active');
                }
            },
            inactive(ctx) {
                const { button, panel } = ctx;
                razyui(button).setAttr({ 'aria-selected': 'false', tabindex: '-1' })
                    .removeClass('is-active');
                if (panel) {
                    razyui(panel).removeClass('is-active');
                    panel.hidden = true;
                }
            },
            disabled(ctx) {
                ctx.button.disabled = true;
                razyui(ctx.button).addClass('is-disabled')
                    .setAttr({ 'aria-disabled': 'true' });
            },
            'disabled:exit'(ctx) {
                ctx.button.disabled = false;
                razyui(ctx.button).removeClass('is-disabled');
                ctx.button.removeAttribute('aria-disabled');
            },
        },
    },

    // ═════════════════════════════════════
    //  Template Slots
    // ═════════════════════════════════════
    template: {
        slots: {
            root:  { element: 'div',    classes: ['tabs'],         role: null },
            list:  { element: 'div',    classes: ['tabs-list'],    role: 'tablist' },
            tab:   { element: 'button', classes: ['tabs-tab'],     role: 'tab' },
            panel: { element: 'div',    classes: ['tabs-panel'],   role: 'tabpanel' },
        },
    },

    jitParts: {
        [PART.ROOT]: PART.ROOT,
        [PART.LIST]: PART.LIST,
        [PART.TAB]: PART.TAB,
        [PART.PANEL]: PART.PANEL,
        [PART.ICON]: PART.ICON,
        [PART.CLOSE]: PART.CLOSE,
        [PART.VERT_ROOT]: PART.VERT_ROOT,
        [PART.VERT_LIST]: PART.VERT_LIST,
        [PART.BOXED_ROOT]: PART.BOXED_ROOT,
        [PART.BOXED_TAB]: PART.BOXED_TAB,
        [PART.PILLS_ROOT]: PART.PILLS_ROOT,
        [PART.PILLS_TAB]: PART.PILLS_TAB,
    },

    styles: {},

    // ═════════════════════════════════════
    //  Event Handlers
    // ═════════════════════════════════════
    handlers: {
        tab: {
            click(ctx, e) {
                // Handle close button click
                const closeBtn = e.target.closest(SEL.CLOSE);
                if (closeBtn) {
                    const tab = closeBtn.closest(SEL.TAB);
                    if (tab) {
                        e.preventDefault();
                        e.stopPropagation();
                        const idx = ctx.tabs.indexOf(tab);
                        if (idx >= 0) ctx.close(idx);
                    }
                    return;
                }

                const btn = e.target.closest(SEL.TAB);
                if (!btn || btn.disabled || !ctx.tabs.includes(btn)) return;
                e.preventDefault();
                ctx.select(ctx.tabs.indexOf(btn));
                btn.focus();
            },

            keydown(ctx, e) {
                const idx = ctx.activeIndex;
                const isVertical = ctx.orientation === 'vertical';
                let target = -1;

                switch (e.key) {
                    case 'ArrowRight':
                        if (isVertical) return;
                        e.preventDefault();
                        target = ctx.findNextTab(idx, 1);
                        break;
                    case 'ArrowLeft':
                        if (isVertical) return;
                        e.preventDefault();
                        target = ctx.findNextTab(idx, -1);
                        break;
                    case 'ArrowDown':
                        if (!isVertical) return;
                        e.preventDefault();
                        target = ctx.findNextTab(idx, 1);
                        break;
                    case 'ArrowUp':
                        if (!isVertical) return;
                        e.preventDefault();
                        target = ctx.findNextTab(idx, -1);
                        break;
                    case 'Home':
                        e.preventDefault();
                        target = ctx.findNextTab(-1, 1);
                        break;
                    case 'End':
                        e.preventDefault();
                        target = ctx.findNextTab(ctx.tabs.length, -1);
                        break;
                    default: return;
                }

                if (target >= 0) {
                    if (ctx.activation === 'automatic') {
                        ctx.select(target);
                    }
                    ctx.tabs[target].focus();
                }
            },
        },
    },

    // ═════════════════════════════════════
    //  Variants
    // ═════════════════════════════════════
    variants: {
        boxed:    { description: 'Bordered card style with individual tab borders' },
        pills:    { description: 'Rounded pill-style tabs within an inset container' },
        vertical: { description: 'Tabs stacked vertically on the left side' },
    },

    // ═════════════════════════════════════
    //  Custom Element
    // ═════════════════════════════════════
    observedAttrs: ['active', 'variant', 'orientation', 'activation', 'closable'],
    attrMap: {
        active: 'activeIndex',
        variant: 'variant',
        orientation: 'orientation',
        activation: 'activation',
        closable: 'closable',
    },
};

export default TabsDef;
