/**
 * @fileoverview Tabs view — DOM setup / teardown and state-machine effects.
 * @module module/Tabs/view
 */

import razyui from '../../index.js';
import { CLS, ARIA, PART } from './constants.js';

// ═══════════════════════════════════════
//  State Machine Effects (DOM updates)
// ═══════════════════════════════════════

/**
 * SM effects keyed by state name. Consumed by StateMachine via
 * `{ ...TAB_TRANSITIONS, effects: SM_EFFECTS }`.
 */
export const SM_EFFECTS = {
    /** Entry effect — tab becomes active */
    active({ button, panel }) {
        button.setAttr({
            'aria-selected': 'true',
            'tabindex': '0',
        }).addClass(CLS.ACTIVE);

        if (panel) {
            panel.show().addClass(CLS.ACTIVE);
        }
    },

    /** Entry effect — tab becomes inactive */
    inactive({ button, panel }) {
        button.setAttr({
            'aria-selected': 'false',
            'tabindex': '-1',
        }).removeClass(CLS.ACTIVE);

        if (panel) {
            panel.removeClass(CLS.ACTIVE).hide();
        }
    },

    /** Entry effect — tab becomes disabled */
    disabled(ctx) {
        ctx.button.addClass(CLS.DISABLED)
            .setAttr({ 'aria-disabled': 'true', disabled: true });
        if (ctx.panel) ctx.panel.removeClass(CLS.ACTIVE).hide();
    },

    /** Exit effect — leaving disabled state (re-enable) */
    'disabled:exit'(ctx) {
        ctx.button.removeClass(CLS.DISABLED)
            .removeAttr('aria-disabled')
            .setAttr({ disabled: false });
    },
};

// ═══════════════════════════════════════
//  DOM Setup
// ═══════════════════════════════════════

/**
 * Set up root container with variant & orientation classes.
 *
 * @param {HTMLElement} root — the outer container
 * @param {object} config — { variant, orientation }
 */
export function setupRoot(root, config) {
    const { variant, orientation } = config;
    root.addClass(CLS.ROOT);
    PART.ROOT.apply(root);

    if (orientation === 'vertical') {
        root.addClass(CLS.VERTICAL);
        PART.VERT_ROOT.apply(root);
    }

    if (variant === 'boxed') {
        PART.BOXED_ROOT.apply(root);
    } else if (variant === 'pills') {
        PART.PILLS_ROOT.apply(root);
    }
}

/**
 * Set up ARIA role on the tab list container (the <nav> or list wrapper).
 *
 * @param {HTMLElement} list — tab list element
 * @param {object} config — { variant, orientation }
 */
export function setupList(list, config) {
    const { variant, orientation } = config;
    list.setAttr({ role: ARIA.TABLIST }).addClass(CLS.LIST);
    PART.LIST.apply(list);

    if (orientation === 'vertical') {
        list.setAttr({ 'aria-orientation': 'vertical' });
        PART.VERT_LIST.apply(list);
    }
}

/**
 * Set up ARIA linking between a tab button and its panel.
 *
 * @param {HTMLElement} btn   — tab button (razyui-wrapped)
 * @param {HTMLElement} panel — associated panel (razyui-wrapped)
 * @param {number} uid       — unique tabs instance id
 * @param {number} index     — tab index
 * @param {object} config    — { variant, closable }
 */
export function setupTabARIA(btn, panel, uid, index, config) {
    const { variant, closable } = config;
    const tabId   = btn.attr('id')   || `tabs-${uid}-${index}`;
    const panelId = panel.attr('id') || `tabs-panel-${uid}-${index}`;

    btn.attr('id', tabId);
    panel.attr('id', panelId);

    btn.setAttr({
        'role':         ARIA.TAB,
        'aria-controls': panelId,
        'aria-selected': 'false',
        'tabindex':     '-1',
    });

    PART.TAB.apply(btn);

    if (variant === 'boxed') {
        PART.BOXED_TAB.apply(btn);
    } else if (variant === 'pills') {
        PART.PILLS_TAB.apply(btn);
    }

    // Append close button if closable
    if (closable && !btn.find('.' + CLS.CLOSE).length) {
        const closeEl = document.createElement('span');
        closeEl.className = CLS.CLOSE;
        closeEl.setAttribute('aria-label', 'Close tab');
        closeEl.textContent = '×';
        btn.append(closeEl);
        PART.CLOSE.apply(razyui(closeEl));
    }

    panel.setAttr({
        'role': ARIA.TABPANEL,
        'aria-labelledby': tabId,
    }).hide();

    PART.PANEL.apply(panel);
}

// ═══════════════════════════════════════
//  DOM Teardown
// ═══════════════════════════════════════

/**
 * Remove all ARIA attributes, roles, and classes added by the Tabs component.
 *
 * @param {HTMLElement} root — root container
 * @param {HTMLElement} list — the tab list
 * @param {HTMLElement[]} tabs — tab button elements
 * @param {Map<HTMLElement, HTMLElement>} panels — tab → panel map
 * @param {object} config — { variant, orientation }
 */
export function cleanupDOM(root, list, tabs, panels, config) {
    const { variant, orientation } = config;

    root.removeClass(CLS.ROOT, CLS.VERTICAL);
    PART.ROOT.unapply(root);
    PART.VERT_ROOT.unapply(root);
    PART.BOXED_ROOT.unapply(root);
    PART.PILLS_ROOT.unapply(root);

    list.removeAttr('role', 'aria-orientation')
        .removeClass(CLS.LIST);
    PART.LIST.unapply(list);
    PART.VERT_LIST.unapply(list);

    tabs.forEach(btn => {
        const $btn = razyui(btn);
        $btn.removeAttr('role', 'aria-controls', 'aria-selected', 'tabindex', 'aria-disabled')
            .removeClass(CLS.TAB, CLS.ACTIVE, CLS.DISABLED);
        PART.TAB.unapply($btn);
        PART.BOXED_TAB.unapply($btn);
        PART.PILLS_TAB.unapply($btn);

        const panel = panels.get(btn);
        if (panel) {
            panel.removeAttr('role', 'aria-labelledby')
                .removeClass(CLS.PANEL, CLS.ACTIVE);
            PART.PANEL.unapply(panel);
            panel.show();
        }
    });
}
